const item = $input.first().json;

function extractJson(value) {
  if (value && typeof value === 'object' && (value.source_list || value.key_findings || value.document_title)) {
    return value;
  }

  const raw = String(value?.response || value?.text || value?.output || value?.result || value?.message?.content || '').trim();
  if (!raw) throw new Error('AI did not return text or structured JSON.');

  const cleaned = raw
    .replace(/^```[a-zA-Z]*\n?/, '')
    .replace(/```$/, '')
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch (_) {
    const firstBrace = cleaned.indexOf('{');
    const lastBrace = cleaned.lastIndexOf('}');
    if (firstBrace >= 0 && lastBrace > firstBrace) {
      return JSON.parse(cleaned.slice(firstBrace, lastBrace + 1));
    }
  }

  throw new Error('AI did not return usable JSON. Rerun the workflow or use a model that supports JSON output.');
}

function asList(value, fallback) {
  if (Array.isArray(value)) {
    const cleaned = value.map((item) => String(item).trim()).filter(Boolean);
    if (cleaned.length) return cleaned;
  }
  if (typeof value === 'string' && value.trim()) {
    return value.split('\n').map((item) => item.replace(/^[-*]\s*/, '').trim()).filter(Boolean);
  }
  return fallback;
}

function bulletList(items) {
  return asList(items, ['None added.']).map((item) => '- ' + item).join('\n');
}

function sourceMarkdown(sources) {
  if (!Array.isArray(sources) || sources.length === 0) return '- No sources were extracted.';
  return sources.map((source, index) => {
    if (typeof source === 'string') return `${index + 1}. ${source}`;
    return [
      `${index + 1}. **${String(source.source || 'Unlabeled source').trim()}**`,
      `   - Type: ${String(source.source_type || 'unknown').trim()}`,
      `   - Provided context: ${String(source.provided_context || 'No context provided.').trim()}`,
      `   - Verification needed: ${String(source.verification_needed || 'Verify before relying on this source.').trim()}`
    ].join('\n');
  }).join('\n');
}

function themeMarkdown(themes) {
  if (!Array.isArray(themes) || themes.length === 0) return '- No themes were extracted.';
  return themes.map((theme) => {
    if (typeof theme === 'string') return `### ${theme}\n- No notes added.`;
    return [
      `### ${String(theme.theme || 'Untitled Theme').trim()}`,
      bulletList(theme.notes || ['No notes added.']),
      '',
      `**Why it matters:** ${String(theme.why_it_matters || 'Review this theme against the research goal.').trim()}`
    ].join('\n');
  }).join('\n\n');
}

const parsed = extractJson(item);
const sourceList = Array.isArray(parsed.source_list) ? parsed.source_list : [];
const keyFindings = asList(parsed.key_findings, ['Review the provided notes and add confirmed findings.']);
const assumptions = asList(parsed.assumptions_or_uncertainties, ['Any source content not pasted into this workflow still needs verification.']);
const followUpQuestions = asList(parsed.follow_up_questions, ['What source should be reviewed next?']);
const nextActions = asList(parsed.recommended_next_actions || parsed.next_steps, ['Open and verify each saved source.', 'Add excerpts or notes from the strongest sources.', 'Turn confirmed findings into a draft or decision brief.']);
while (nextActions.length < 3) {
  const fillIns = ['Open and verify each saved source.', 'Add excerpts or notes from the strongest sources.', 'Turn confirmed findings into a draft or decision brief.'];
  const next = fillIns.find((item) => !nextActions.includes(item));
  if (!next) break;
  nextActions.push(next);
}
const tags = asList(parsed.knowledge_base_tags, ['research', 'source-review']);

const markdown = [
  '## Research Topic',
  String(parsed.research_topic || 'Untitled research topic').trim(),
  '',
  '## Source List',
  sourceMarkdown(sourceList),
  '',
  '## Key Findings',
  bulletList(keyFindings),
  '',
  '## Themes',
  themeMarkdown(parsed.themes),
  '',
  '## Assumptions or Uncertainties',
  bulletList(assumptions),
  '',
  '## Follow-Up Questions',
  bulletList(followUpQuestions),
  '',
  '## Knowledge Base Tags',
  tags.map((tag) => `#${String(tag).replace(/^#/, '').replace(/\s+/g, '-').toLowerCase()}`).join(' ')
].join('\n');

return [{
  json: {
    workflow_name: 'GP-WF-007 - Research Collector',
    created_at: new Date().toISOString(),
    document_title: String(parsed.document_title || 'Research Collection Brief').trim(),
    summary: String(parsed.summary || 'Organized saved sources and notes into a research brief.').trim(),
    output_markdown: markdown,
    source_count: sourceList.length,
    key_findings: keyFindings,
    assumptions_or_uncertainties: assumptions,
    follow_up_questions: followUpQuestions,
    next_steps: nextActions,
    knowledge_base_tags: tags,
    review_note: String(parsed.review_note || 'Verify source content before treating this research brief as complete.').trim()
  }
}];

const today = new Date();
const date = today.toISOString().slice(0, 10);
const nextSteps = Array.isArray($json.next_steps) ? $json.next_steps : [];

const body = [
  `# ${$json.document_title || 'Research Collection Brief'}`,
  '',
  `Created: ${date}`,
  'Workflow: GP-WF-007 - Research Collector',
  '',
  '## Summary',
  $json.summary || 'No summary returned.',
  '',
  $json.output_markdown || '',
  '',
  '## Recommended Next Actions',
  ...(nextSteps.length ? nextSteps.map((step) => `- ${step}`) : ['- Verify each source and add missing context.']),
  '',
  '## Human Review Note',
  $json.review_note || 'Verify sources before using this research brief.',
  '',
  'Source: GetPrompting Free Workflow Library'
].join('\n');

return [{
  json: {
    ...$json,
    document_title: `GP-WF-007 - Research Collector - ${date}`,
    document_body: body
  }
}];
